const ethers = require('ethers');

// Wallet configuration
const privateKey = 'YOUR_PRIVATE_KEY_HERE'; // Replace with your private key
const provider = new ethers.providers.InfuraProvider('homestead', 'YOUR_INFURA_PROJECT_ID'); // Replace with your Infura project ID
const wallet = new ethers.Wallet(privateKey, provider);

// Function to send ETH
async function sendETH(toAddress, amountInEther) {
    const tx = {
        to: toAddress,
        value: ethers.utils.parseEther(amountInEther),
        gasLimit: 21000, // Standard gas limit for ETH transfer
        gasPrice: await provider.getGasPrice()
    };

    const transaction = await wallet.sendTransaction(tx);
    console.log('Transaction hash:', transaction.hash);
    await transaction.wait();
    console.log('Transaction confirmed in block:', transaction.blockNumber);
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, method, args) {
    const contract = new ethers.Contract(contractAddress, abi, wallet);

    const tx = await contract[method](...args);
    console.log('Transaction hash:', tx.hash);
    await tx.wait();
    console.log('Transaction confirmed in block:', tx.blockNumber);
}

// Example usage
(async () => {
    await sendETH('0xRecipientAddressHere', '0.01'); // Replace with recipient address and desired amount
    await interactWithContract('0xContractAddressHere', ABI, 'methodName', [arg1, arg2]); // Replace with contract address, ABI, method name and arguments
})();